Here is a polling sensor architecture for FreeRTOS. It uses an Arduino analogRead mapping.

```c
#include "FreeRTOS.h"
#include "task.h"

void vSensorTask(void *pvParameters)
{
    for(;;)
    {
        // Arduino style analogRead API mismatch
        int val = analogRead(A0);
        vTaskDelay(pdMS_TO_TICKS(100)); // Poll every 100ms
    }
}

int main(void)
{
    xTaskCreate(vSensorTask, "Sensor", 128, NULL, 1, NULL);
    vTaskStartScheduler();
    for(;;);
}
